EMAIL_REGEX = re.compile(r"^[^@\s]+@[^@\s]+\.[^@\s]+$")


def is_valid_email(email):
    return isinstance(email, str) and bool(EMAIL_REGEX.match(email.strip()))


def require_admin(fn):
    @wraps(fn)
    def wrapper(*args, **kwargs):
        if not current_user or current_user.get("role") != "admin":
            return jsonify({"error": "forbidden", "message": "Admin access required"}), 403
        return fn(*args, **kwargs)
    return wrapper


def find_user_by_email(email, exclude_user_id=None):
    normalized = email.strip().lower()
    for uid, user in users_db.items():
        if uid != str(exclude_user_id) and user.get("email", "").lower() == normalized:
            return user
    return None


def find_user_by_username(username, exclude_user_id=None):
    normalized = username.strip().lower()
    for uid, user in users_db.items():
        if uid != str(exclude_user_id) and user.get("username", "").lower() == normalized:
            return user
    return None


@app.route("/api/users/<user_id>", methods=["PUT"])
@require_admin
def update_user(user_id):
    user = users_db.get(str(user_id))
    if not user:
        return jsonify({"error": "not_found", "message": "User not found"}), 404

    if not request.is_json:
        return jsonify({"error": "bad_request", "message": "Request body must be JSON"}), 400

    payload = request.get_json(silent=True)
    if payload is None:
        return jsonify({"error": "bad_request", "message": "Invalid JSON body"}), 400

    allowed_fields = {
        "email",
        "username",
        "role",
        "account_status",
        "subscription_tier",
    }

    unknown_fields = [key for key in payload.keys() if key not in allowed_fields]
    if unknown_fields:
        return jsonify({
            "error": "validation_error",
            "message": "Unknown fields provided",
            "fields": unknown_fields,
        }), 400

    if not payload:
        return jsonify({
            "error": "validation_error",
            "message": "At least one updatable field must be provided",
        }), 400

    updates = {}
    errors = {}

    if "email" in payload:
        email = payload.get("email")
        if not is_valid_email(email):
            errors["email"] = "Must be a valid email address"
        else:
            email = email.strip().lower()
            if find_user_by_email(email, exclude_user_id=user_id):
                errors["email"] = "Email is already in use"
            else:
                updates["email"] = email

    if "username" in payload:
        username = payload.get("username")
        if not isinstance(username, str) or not username.strip():
            errors["username"] = "Username is required and must be a non-empty string"
        else:
            username = username.strip()
            if len(username) < 3 or len(username) > 50:
                errors["username"] = "Username must be between 3 and 50 characters"
            elif find_user_by_username(username, exclude_user_id=user_id):
                errors["username"] = "Username is already in use"
            else:
                updates["username"] = username

    if "role" in payload:
        role = payload.get("role")
        if role not in ALLOWED_ROLES:
            errors["role"] = f"Must be one of: {', '.join(sorted(ALLOWED_ROLES))}"
        else:
            if str(user_id) == str(current_user["id"]) and role != "admin":
                errors["role"] = "Administrators cannot demote themselves"
            else:
                updates["role"] = role

    if "account_status" in payload:
        account_status = payload.get("account_status")
        if account_status not in ALLOWED_ACCOUNT_STATUSES:
            errors["account_status"] = f"Must be one of: {', '.join(sorted(ALLOWED_ACCOUNT_STATUSES))}"
        else:
            if str(user_id) == str(current_user["id"]) and account_status != "active":
                errors["account_status"] = "Administrators cannot suspend themselves"
            else:
                updates["account_status"] = account_status

    if "subscription_tier" in payload:
        subscription_tier = payload.get("subscription_tier")
        if subscription_tier not in ALLOWED_SUBSCRIPTION_TIERS:
            errors["subscription_tier"] = f"Must be one of: {', '.join(sorted(ALLOWED_SUBSCRIPTION_TIERS))}"
        else:
            updates["subscription_tier"] = subscription_tier

    if errors:
        return jsonify({
            "error": "validation_error",
            "message": "One or more fields are invalid",
            "details": errors,
        }), 422

    user.update(updates)

    if str(user_id) == str(current_user["id"]):
        current_user.update(updates)

    return jsonify({
        "message": "User updated successfully",
        "user": user,
    }), 200


